      @keyframes fb_mpn_landing_page_slide_out {
        0% {
          margin: 0 12px;
          width: 100% - 24px
        }

        60% {
          border-radius: 18px
        }

        100% {
          border-radius: 50%;
          margin: 0 24px;
          width: 60px
        }
      }

      @keyframes fb_mpn_landing_page_slide_out_from_left {
        0% {
          left: 12px;
          width: 100% - 24px
        }

        60% {
          border-radius: 18px
        }

        100% {
          border-radius: 50%;
          left: 12px;
          width: 60px
        }
      }

      @keyframes fb_mpn_landing_page_slide_up {
