          top: 100%
        }

        100% {
          opacity: 1;
          top: 0
        }
      }

      @keyframes fb_mpn_fade_out {
        0% {
          bottom: 30px;
          opacity: 1
        }

        100% {
          bottom: 0;
          opacity: 0
        }
      }

      @keyframes fb_mpn_bounce_out {
        0% {
          opacity: 1;
          top: 0
        }

        100% {
          opacity: .5;
          top: 100%
        }
      }

      @keyframes fb_bounce_in_v2 {
        0% {
          opacity: 0;
          transform: scale(0, 0);
          transform-origin: bottom right
        }

        50% {
          transform: scale(1.03, 1.03);
          transform-origin: bottom right
        }

        100% {
          opacity: 1;
          transform: scale(1, 1);
          transform-origin: bottom right
        }
      }

      @keyframes fb_bounce_in_from_left {
        0% {
          opacity: 0;
          transform: scale(0, 0);
          transform-origin: bottom left
        }

        50% {
          transform: scale(1.03, 1.03);
          transform-origin: bottom left
        }

        100% {
          opacity: 1;
          transform: scale(1, 1);
          transform-origin: bottom left
        }
      }

      @keyframes fb_bounce_out_v2 {
        0% {
          opacity: 1;
          transform: scale(1, 1);
          transform-origin: bottom right
        }

        100% {
          opacity: 0;
          transform: scale(0, 0);
          transform-origin: bottom right
        }
      }

      @keyframes fb_bounce_out_from_left {
        0% {
          opacity: 1;
          transform: scale(1, 1);
          transform-origin: bottom left
        }

        100% {
          opacity: 0;
          transform: scale(0, 0);
          transform-origin: bottom left
        }
      }

      @keyframes slideInFromBottom {
        0% {
          opacity: .1;
          transform: translateY(100%)
        }

        100% {
          opacity: 1;
          transform: translateY(0)
        }
      }

      @keyframes slideInFromBottomDelay {
        0% {
          opacity: 0;
          transform: translateY(100%)
        }

        97% {
          opacity: 0;
          transform: translateY(100%)
        }

        100% {
          opacity: 1;
          transform: translateY(0)
        }
      }
